-- 30 kunlik so'zlar (600 ta) - word_entries jadvaliga INSERT
-- Supabase SQL Editor da ishlatish uchun
-- MUHIM: avval 04_create_word_entries.sql ni ishga tushiring

-- Avval 1-30 kunlar uchun mavjud so'zlarni tozalash
DELETE FROM word_entries WHERE day_number BETWEEN 1 AND 30;


-- Tekshirish
SELECT day_number, COUNT(*) as count FROM word_entries WHERE day_number BETWEEN 1 AND 30 GROUP BY day_number ORDER BY day_number;
